// NEW BOOKING — extract key details
const body = $input.first().json.body || $input.first().json;
const data = body.data || {};

return [{
  json: {
    event: 'New Booking!',
    guest: data.guestName || data.guest || 'Unknown',
    email: data.email || '',
    confirmationNumber: data.confirmationNumber || data.confirmation || '',
    roomType: data.roomType || '',
    checkIn: data.checkIn || '',
    checkOut: data.checkOut || '',
    total: data.total || data.amount || '',
    timestamp: body.timestamp || new Date().toISOString()
  }
}];

// RATE ALERT — extract pricing details
const body = $input.first().json.body || $input.first().json;
const data = body.data || {};

return [{
  json: {
    event: 'Rate Alert!',
    roomType: data.roomType || '',
    ourRate: data.ourRate || '',
    otaLowest: data.otaLowest || data.lowestOTA || '',
    platform: data.platform || '',
    action: data.status === 'beating' ? 'We are beating OTA' : 'PRICE ADJUSTMENT NEEDED',
    timestamp: body.timestamp || new Date().toISOString()
  }
}];

// POST-STAY — extract guest details
const body = $input.first().json.body || $input.first().json;
const data = body.data || {};

return [{
  json: {
    event: 'Post Stay Follow-up',
    guest: data.guestName || data.guest || 'Unknown',
    email: data.email || '',
    stayDates: `${data.checkIn || '?'} to ${data.checkOut || '?'}`,
    loyaltyPoints: data.loyaltyPoints || 0,
    timestamp: body.timestamp || new Date().toISOString()
  }
}];

// TOUR PRICE UPDATE — extract details
const body = $input.first().json.body || $input.first().json;
const data = body.data || {};

return [{
  json: {
    event: 'Tour Prices Updated',
    toursUpdated: data.count || data.toursUpdated || 0,
    avgSavings: data.avgSavings || '',
    timestamp: body.timestamp || new Date().toISOString()
  }
}];

// CATCH-ALL for unknown events
const body = $input.first().json.body || $input.first().json;

return [{
  json: {
    event: 'Unknown Event',
    workflow: body.workflow || 'unknown',
    rawData: JSON.stringify(body.data || {}).substring(0, 500),
    timestamp: body.timestamp || new Date().toISOString()
  }
}];
